import React, { useState, useEffect, useMemo } from 'react';
import { Container, Row, Col, Card, Table, Badge, Alert } from 'react-bootstrap';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, ReferenceLine } from 'recharts';

interface DataPoint {
  tiempo: number;
  ventas: number;
  derivada: number;
  creciendo: boolean;
}

interface GrowthPeriod {
  inicio: number;
  fin: number;
  ventasInicio: number;
  ventasFin: number;
  aumento: number;
}

export const AnalisisVentas: React.FC = () => {
  const [data, setData] = useState<DataPoint[]>([]);
  const [growthPeriods, setGrowthPeriods] = useState<GrowthPeriod[]>([]);
  const [stats, setStats] = useState({
    ventasPromedio: 0,
    ventaMaxima: 0,
    ventaMinima: 0,
    totalPeriodosCrecimiento: 0,
    porcentajeTiempoCreciendo: 0
  });

  // Función de ventas: f(t) = 20 + 5*sin(t)
  const calcularVentas = (t: number): number => {
    return 20 + 5 * Math.sin(t);
  };

  // Derivada: f'(t) = 5*cos(t)
  const calcularDerivada = (t: number): number => {
    return 5 * Math.cos(t);
  };

  useEffect(() => {
    // Generar datos para el rango t = 0 a 10 con pasos de 0.1
    const puntos: DataPoint[] = [];
    for (let t = 0; t <= 10; t += 0.1) {
      const tRedondeado = Math.round(t * 10) / 10;
      const ventas = calcularVentas(tRedondeado);
      const derivada = calcularDerivada(tRedondeado);
      puntos.push({
        tiempo: tRedondeado,
        ventas: Math.round(ventas * 100) / 100,
        derivada: Math.round(derivada * 100) / 100,
        creciendo: derivada > 0
      });
    }
    setData(puntos);

    // Identificar períodos de crecimiento
    const periodos: GrowthPeriod[] = [];
    let inicioCrecimiento: number | null = null;
    let ventasInicio = 0;

    puntos.forEach((punto, index) => {
      if (punto.creciendo && inicioCrecimiento === null) {
        // Inicio de un período de crecimiento
        inicioCrecimiento = punto.tiempo;
        ventasInicio = punto.ventas;
      } else if (!punto.creciendo && inicioCrecimiento !== null) {
        // Fin de un período de crecimiento
        const periodo: GrowthPeriod = {
          inicio: inicioCrecimiento,
          fin: punto.tiempo,
          ventasInicio: Math.round(ventasInicio * 100) / 100,
          ventasFin: Math.round(punto.ventas * 100) / 100,
          aumento: Math.round((punto.ventas - ventasInicio) * 100) / 100
        };
        periodos.push(periodo);
        inicioCrecimiento = null;
      }
    });

    // Si termina en crecimiento, cerrar el último período
    if (inicioCrecimiento !== null) {
      const ultimoPunto = puntos[puntos.length - 1];
      periodos.push({
        inicio: inicioCrecimiento,
        fin: ultimoPunto.tiempo,
        ventasInicio: Math.round(ventasInicio * 100) / 100,
        ventasFin: ultimoPunto.ventas,
        aumento: Math.round((ultimoPunto.ventas - ventasInicio) * 100) / 100
      });
    }

    setGrowthPeriods(periodos);

    // Calcular estadísticas
    const ventasArray = puntos.map(p => p.ventas);
    const totalPuntos = puntos.length;
    const puntosCreciendo = puntos.filter(p => p.creciendo).length;

    setStats({
      ventasPromedio: Math.round((ventasArray.reduce((a, b) => a + b, 0) / totalPuntos) * 100) / 100,
      ventaMaxima: Math.round(Math.max(...ventasArray) * 100) / 100,
      ventaMinima: Math.round(Math.min(...ventasArray) * 100) / 100,
      totalPeriodosCrecimiento: periodos.length,
      porcentajeTiempoCreciendo: Math.round((puntosCreciendo / totalPuntos) * 100)
    });
  }, []);

  // ============================================
  // TRANSFORMADA DE LAPLACE
  // ============================================
  // Para f(t) = 20 + 5*sin(t):
  // L{20} = 20/s
  // L{5*sin(t)} = 5/(s² + 1)
  // F(s) = 20/s + 5/(s² + 1)

  const calcularTransformadaLaplace = (sigma: number, omega: number): number => {
    const s = sigma + omega; // s = σ + jω (tomamos la parte real para visualización)
    if (s === 0) return 0;
    const term1 = 20 / s;           // L{20}
    const term2 = 5 / (s * s + 1);  // L{5*sin(t)}
    return term1 + term2;
  };

  // Generar datos de la Transformada de Laplace para visualización
  const datosLaplace = useMemo(() => {
    const puntos = [];
    for (let sigma = 0.1; sigma <= 5; sigma += 0.1) {
      // Mostramos la magnitud |F(s)| para diferentes valores de s = σ
      const valor = calcularTransformadaLaplace(sigma, 0);
      puntos.push({
        sigma: Math.round(sigma * 10) / 10,
        magnitud: Math.round(valor * 100) / 100,
        terminoConstante: Math.round((20 / sigma) * 100) / 100,
        terminoSinusoidal: Math.round((5 / (sigma * sigma + 1)) * 100) / 100
      });
    }
    return puntos;
  }, []);

  // Proyección usando Inversa de Laplace (estimación futura)
  // Para periodos futuros, extendemos la función periódica
  const datosProyeccion = useMemo(() => {
    const puntos = [];
    // Datos históricos (t = 0 a 10)
    for (let t = 0; t <= 10; t += 0.5) {
      const tRedondeado = Math.round(t * 10) / 10;
      puntos.push({
        tiempo: tRedondeado,
        tipo: 'Histórico',
        ventas: Math.round(calcularVentas(tRedondeado) * 100) / 100
      });
    }
    // Proyección futura usando periodicidad (t = 10 a 20)
    for (let t = 10.5; t <= 20; t += 0.5) {
      const tRedondeado = Math.round(t * 10) / 10;
      // Usamos la periodicidad: sin(t) = sin(t - 2πn) donde n es el número de periodos
      const tEquivalente = tRedondeado % (2 * Math.PI);
      puntos.push({
        tiempo: tRedondeado,
        tipo: 'Proyección (Laplace)',
        ventas: Math.round(calcularVentas(tEquivalente) * 100) / 100
      });
    }
    return puntos;
  }, []);

  // Encontrar puntos críticos donde f'(t) = 0 (cos(t) = 0)
  const puntosCriticos = useMemo(() => {
    // cos(t) = 0 cuando t = π/2 + nπ, para n = 0, 1, 2...
    // En el rango [0, 10]: π/2 ≈ 1.57, 3π/2 ≈ 4.71, 5π/2 ≈ 7.85
    const puntos = [];
    let n = 0;
    while (true) {
      const t = Math.PI / 2 + n * Math.PI;
      if (t > 10) break;
      puntos.push({
        tiempo: Math.round(t * 100) / 100,
        tipo: n % 2 === 0 ? 'Máximo' : 'Mínimo',
        valor: calcularVentas(t)
      });
      n++;
    }
    return puntos;
  }, []);

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="custom-tooltip" style={{ 
          backgroundColor: 'white', 
          padding: '10px', 
          border: '1px solid #ccc',
          borderRadius: '8px'
        }}>
          <p style={{ margin: '0 0 5px 0', fontWeight: 'bold' }}>t = {label}</p>
          <p style={{ margin: '0', color: '#6B8E6B' }}>
            Ventas: f(t) = {payload[0].value}
          </p>
          <p style={{ margin: '0', color: '#8FA4B8' }}>
            Derivada: f'(t) = {payload[1]?.value}
          </p>
          <p style={{ margin: '5px 0 0 0', fontSize: '12px' }}>
            {payload[1]?.value > 0 ? 'Creciendo' : payload[1]?.value < 0 ? 'Decreciendo' : 'Estable'}
          </p>
        </div>
      );
    }
    return null;
  };

  return (
    <Container className="py-5">
      {/* Header */}
      <div className="text-center mb-5">
        <h1 className="section-title" style={{ fontSize: '2.5rem', fontWeight: 700 }}>
          Análisis de Ventas con Transformada de Laplace
        </h1>
        <p className="section-description" style={{ maxWidth: '800px', margin: '0 auto' }}>
          Identificación de momentos de crecimiento para optimizar inventario, 
          producción y estrategias de venta
        </p>
      </div>

      {/* Ecuaciones */}
      <Row className="mb-4">
        <Col md={6}>
          <Card className="h-100" style={{ background: 'var(--neutral-light)', border: 'none' }}>
            <Card.Body>
              <h5 style={{ color: 'var(--primary-color)', fontWeight: 600 }}>
                Funcion de Ventas
              </h5>
              <div className="p-3 bg-white rounded" style={{ fontFamily: 'monospace', fontSize: '1.2rem' }}>
                f(t) = 20 + 5·sin(t)
              </div>
              <p className="mt-2 mb-0 text-muted">
                Representa las ventas en función del tiempo
              </p>
            </Card.Body>
          </Card>
        </Col>
        <Col md={6}>
          <Card className="h-100" style={{ background: 'var(--neutral-light)', border: 'none' }}>
            <Card.Body>
              <h5 style={{ color: 'var(--secondary-color)', fontWeight: 600 }}>
                Derivada (Tasa de Cambio)
              </h5>
              <div className="p-3 bg-white rounded" style={{ fontFamily: 'monospace', fontSize: '1.2rem' }}>
                f'(t) = 5·cos(t)
              </div>
              <p className="mt-2 mb-0 text-muted">
                Indica cuándo las ventas aumentan o disminuyen
              </p>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Estadísticas */}
      <Row className="mb-4">
        <Col lg={3} md={6} className="mb-3">
          <Card style={{ background: 'var(--primary-color)', color: 'white', border: 'none' }}>
            <Card.Body className="text-center">
              <h3 style={{ fontSize: '2rem', fontWeight: 700 }}>{stats.ventasPromedio}</h3>
              <p className="mb-0">Ventas Promedio</p>
            </Card.Body>
          </Card>
        </Col>
        <Col lg={3} md={6} className="mb-3">
          <Card style={{ background: 'var(--accent-color)', color: 'white', border: 'none' }}>
            <Card.Body className="text-center">
              <h3 style={{ fontSize: '2rem', fontWeight: 700 }}>{stats.ventaMaxima}</h3>
              <p className="mb-0">Venta Máxima</p>
            </Card.Body>
          </Card>
        </Col>
        <Col lg={3} md={6} className="mb-3">
          <Card style={{ background: 'var(--secondary-color)', color: 'white', border: 'none' }}>
            <Card.Body className="text-center">
              <h3 style={{ fontSize: '2rem', fontWeight: 700 }}>{stats.totalPeriodosCrecimiento}</h3>
              <p className="mb-0">Periodos de Crecimiento</p>
            </Card.Body>
          </Card>
        </Col>
        <Col lg={3} md={6} className="mb-3">
          <Card style={{ background: 'var(--neutral-dark)', color: 'white', border: 'none' }}>
            <Card.Body className="text-center">
              <h3 style={{ fontSize: '2rem', fontWeight: 700 }}>{stats.porcentajeTiempoCreciendo}%</h3>
              <p className="mb-0">Tiempo Creciendo</p>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Gráfica */}
      <Card className="mb-4" style={{ border: 'none', boxShadow: 'var(--card-shadow)' }}>
        <Card.Body>
          <h4 className="mb-4" style={{ color: 'var(--primary-color)', fontWeight: 600 }}>
            Grafica de Ventas y Tasa de Cambio
          </h4>
          <ResponsiveContainer width="100%" height={400}>
            <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="var(--border-color)" />
              <XAxis 
                dataKey="tiempo" 
                label={{ value: 'Tiempo (t)', position: 'insideBottom', offset: -5 }}
                stroke="var(--text-secondary)"
              />
              <YAxis 
                label={{ value: 'Valor', angle: -90, position: 'insideLeft' }}
                stroke="var(--text-secondary)"
              />
              <Tooltip content={<CustomTooltip />} />
              <Legend />
              <ReferenceLine y={20} stroke="#999" strokeDasharray="3 3" label="Media" />
              <Line 
                type="monotone" 
                dataKey="ventas" 
                stroke="#6B8E6B" 
                strokeWidth={3}
                name="Ventas f(t)" 
                dot={false}
                activeDot={{ r: 6 }}
              />
              <Line 
                type="monotone" 
                dataKey="derivada" 
                stroke="#8FA4B8" 
                strokeWidth={2}
                strokeDasharray="5 5"
                name="Derivada f'(t)" 
                dot={false}
              />
            </LineChart>
          </ResponsiveContainer>
          <div className="mt-3">
            <small className="text-muted">
              <strong>Leyenda:</strong> Areas donde f'(t) &gt; 0 (linea azul punteada sobre 0) indican crecimiento de ventas
            </small>
          </div>
        </Card.Body>
      </Card>

      {/* Puntos Críticos */}
      <Row className="mb-4">
        <Col md={6}>
          <Card className="h-100" style={{ border: 'none', boxShadow: 'var(--card-shadow)' }}>
            <Card.Body>
              <h5 style={{ color: 'var(--primary-color)', fontWeight: 600 }}>
